// TODO:
// 1. Create a matchDynamicRoute(path, routes) function
//    Each route has { pattern, component }
//    Return { component, params } or null
// 2. Routes:
//    '/home' -> 'HomePage'
//    '/users/:id' -> 'UserPage'
// 3. Test:
//    '/home' -> Log "Component: HomePage, Params: {}"
//    '/users/5' -> Log "Component: UserPage, Params: {"id":"5"}"
//    '/other' -> Log "No match"

exercises.solution:
function matchDynamicRoute(path, routes) {
  for (const route of routes) {
    const patternParts = route.pattern.split('/');
    const pathParts = path.split('/');

    if (patternParts.length !== pathParts.length) continue;

    const params = {};
    let matched = true;

    for (let i = 0; i < patternParts.length; i++) {
      if (patternParts[i].startsWith(':')) {
        params[patternParts[i].slice(1)] = pathParts[i];
      } else if (patternParts[i] !== pathParts[i]) {
        matched = false;
        break;
      }
    }

    if (matched) return { component: route.component, params };
  }
  return null;
}

const routes = [
  { pattern: '/home', component: 'HomePage' },
  { pattern: '/users/:id', component: 'UserPage' }
];

let result = matchDynamicRoute('/home', routes);
console.log('Component: ' + result.component + ', Params: ' + JSON.stringify(result.params));

result = matchDynamicRoute('/users/5', routes);
console.log('Component: ' + result.component + ', Params: ' + JSON.stringify(result.params));

result = matchDynamicRoute('/other', routes);
console.log(result ? 'Match' : 'No match');

