  if (!path.startsWith(config.path)) {
    console.log('No match');
    return;
  }

  console.log('Layout: ' + config.layout);

  const childPath = path.slice(config.path.length + 1);

  if (!childPath) {
    const index = config.children.find(c => c.index);
    console.log('Page: ' + index.component);
  } else {
    const child = config.children.find(c => c.path === childPath);
    console.log('Page: ' + (child ? child.component : 'NotFound'));
  }
}

